CustomField.formula:
IF( pro_Fixed_Rent_Schedules__c > 0, pro_Fixed_Rent_Schedules__c ,
   IF( pro_Floating_Rent_Schedules__c > 0, pro_Floating_Rent_Schedules__c ,
      IF( pro_PBH_Rent_Schedules__c > 0, pro_PBH_Rent_Schedules__c ,
         IF( pro_Seasonal_Rent_Schedules__c > 0, pro_Seasonal_Rent_Schedules__c , 0)
      )
   )
)
